def median(nums):
    sorted_nums = sorted(nums)
    if len(sorted_nums) == 0:
        return None
    elif len(sorted_nums) % 2 == 1:
        return float(sorted_nums[len(sorted_nums) // 2])
    else:
        index = len(sorted_nums) // 2 - 1
        return (sorted_nums[index] + sorted_nums[index+1]) / 2
